from collections import defaultdict, deque
from typing import Callable, Any

class TaskDAG:
    def __init__(self):
        self.tasks: dict[str, Callable] = {}
        self.dependencies: dict[str, list[str]] = defaultdict(list)
        self.results: dict[str, Any] = {}

    def add_task(self, task_id: str, fn: Callable, depends_on: list[str] = None):
        self.tasks[task_id] = fn
        if depends_on:
            self.dependencies[task_id] = depends_on

    def _topological_sort(self) -> list[str]:
        in_degree = {t: 0 for t in self.tasks}
        for task, deps in self.dependencies.items():
            in_degree[task] = len(deps)
        queue = deque([t for t, d in in_degree.items() if d == 0])
        order = []
        while queue:
            task = queue.popleft()
            order.append(task)
            for other_task, deps in self.dependencies.items():
                if task in deps:
                    in_degree[other_task] -= 1
                    if in_degree[other_task] == 0:
                        queue.append(other_task)
        if len(order) != len(self.tasks):
            raise ValueError("Cycle detected in task dependency graph — cannot execute.")
        return order

    def execute(self) -> dict[str, Any]:
        order = self._topological_sort()
        print(f"Execution order: {order}")
        for task_id in order:
            dep_results = {dep: self.results[dep] for dep in self.dependencies.get(task_id, [])}
            print(f"Running task '{task_id}' with inputs from: {list(dep_results.keys()) or ['none']}")
            self.results[task_id] = self.tasks[task_id](dep_results)
        return self.results

# Example: code generation pipeline
dag = TaskDAG()
dag.add_task("gather_requirements", lambda _: {"requirements": "Build a REST API"})
dag.add_task("write_code", lambda d: {"code": f"# Code for: {d['gather_requirements']['requirements']}"}, depends_on=["gather_requirements"])
dag.add_task("review_code", lambda d: {"approved": True, "notes": f"Reviewed: {d['write_code']['code']}"}, depends_on=["write_code"])
dag.add_task("deploy", lambda d: {"status": "deployed" if d['review_code']['approved'] else "blocked"}, depends_on=["review_code"])

results = dag.execute()
print(results)
